use std::collections::BinaryHeap; impl Solution { pub fn get_number_of_backlog_orders(black_o: Vec<Vec<i32>>) -> i32 { let (mut black_b, mut black_s): (BinaryHeap<(i32, i32)>, BinaryHeap<(i32, i32)>) = (BinaryHeap::new(), BinaryHeap::new()); for black_v in black_o { let (black_p, mut black_a, black_t) = (black_v[0], black_v[1], black_v[2]); if black_t == 0 { while black_a > 0 && !black_s.is_empty() && -black_s.peek().unwrap().0 <= black_p { let (black_sp, mut black_sa) = black_s.pop().unwrap(); let black_m = black_a.min(black_sa); black_a -= black_m; black_sa -= black_m; if black_sa > 0 { black_s.push((black_sp, black_sa)); } } if black_a > 0 { black_b.push((black_p, black_a)); } } else { while black_a > 0 && !black_b.is_empty() && black_b.peek().unwrap().0 >= black_p { let (black_bp, mut black_ba) = black_b.pop().unwrap(); let black_m = black_a.min(black_ba); black_a -= black_m; black_ba -= black_m; if black_ba > 0 { black_b.push((black_bp, black_ba)); } } if black_a > 0 { black_s.push((-black_p, black_a)); } } } ((black_b.iter().map(|x| x.1 as i64).sum::<i64>() + black_s.iter().map(|x| x.1 as i64).sum::<i64>()) % 1_000_000_007) as i32 } }